```git reset``` làm gì. Tôi quen với SVN và Git là một mô hình hoàn toàn mới. Tôi làm quen với Mercurial dễ dàng, nhưng Git thì kỹ thuật hơn nhiều.
Tôi nghĩ ```git reset``` gần với ```hg revert```, nhưng dường như có sự khác biệt. Vui lòng bao gồm giải thích chi tiết về:

* các tùy chọn ```--hard```, ```--soft``` và ```--merge```;
* ký hiệu lạ bạn sử dụng với ```HEAD``` như ```HEAD^``` và ```HEAD~1```;
* các trường hợp sử dụng và quy trình làm việc cụ thể;
* hậu quả đối với bản sao làm việc, ```HEAD``` và mức độ căng thẳng tổng thể của bạn.

```java
import java.io.FileInputStream;
import java.io.IOException;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class MD5Checksum {

    public static String getMD5Checksum(String filename) throws IOException, NoSuchAlgorithmException {
        try (FileInputStream fis = new FileInputStream(filename)) {

            MessageDigest md = MessageDigest.getInstance("MD5");

            byte[] buffer = new byte[8192];
            int bytesRead;
            while ((bytesRead = fis.read(buffer)) != -1) {
                md.update(buffer, 0, bytesRead);
            }

            byte[] digest = md.digest();

            StringBuilder sb = new StringBuilder();
            for (byte b : digest) {
                sb.append(String.format("%02x", b));
            }

            return sb.toString();
        }
    }

    public static void main(String[] args) {
        if (args.length != 1) {
            System.err.println("Usage: java MD5Checksum <filename>");
            return;
        }

        String filename = args[0];

        try {
            String checksum = getMD5Checksum(filename);
            System.out.println("MD5 checksum for " + filename + " is: " + checksum);
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        } catch (NoSuchAlgorithmException e) {
            System.err.println("MD5 algorithm not available: " + e.getMessage());
        }
    }
}
```

