```csharp
using System;
using System.Collections.Generic;

public class NQueens
{
    private int boardSize;
    private List<int[]> solutions = new List<int[]>();

    public NQueens(int size)
    {
        boardSize = size;
    }

    public List<int[]> SolveNQueens()
    {
        SolveNQueensUtil(new int[boardSize], 0);
        return solutions;
    }

    private void SolveNQueensUtil(int[] board, int row)
    {
        if (row == boardSize)
        {
            // Found a solution
            solutions.Add((int[])board.Clone()); // Important: Clone the array!
            return;
        }

        for (int col = 0; col < boardSize; col++)
        {
            if (IsSafe(board, row, col))
            {
                board[row] = col;
                SolveNQueensUtil(board, row + 1);
            }
        }
    }

    private bool IsSafe(int[] board, int row, int col)
    {
        for (int i = 0; i < row; i++)
        {
            // Check column
            if (board[i] == col)
            {
                return false;
            }

            // Check diagonals
            if (Math.Abs(board[i] - col) == row - i)
            {
                return false;
            }
        }

        return true;
    }

    public void PrintBoard(int[] board)
    {
        for (int i = 0; i < boardSize; i++)
        {
            for (int j = 0; j < boardSize; j++)
            {
                if (board[i] == j)
                {
                    Console.Write("Q ");
                }
                else
                {
                    Console.Write(". ");
                }
            }
            Console.WriteLine();
        }
        Console.WriteLine();
    }

    public static void Main(string[] args)
    {
        int n = 8; // Change this to the desired board size (e.g., 8 for a standard chessboard)

        NQueens nQueens = new NQueens(n);
        List<int[]> solutions = nQueens.SolveNQueens();

        Console.WriteLine($"Found {solutions.Count} solutions for {n}-Queens problem:");

        foreach (int[] solution in solutions)
        {
            nQueens.PrintBoard(solution);
        }
    }
}
```

