```csharp
// Mã C# để đặt n quân Hậu
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // kích thước tối đa của bàn cờ
    static int MAX = 10;

    // mảng để lưu trữ vị trí đặt quân hậu
    static int[] arr = new int[MAX];

    // biến để đếm số lượng giải pháp tìm thấy
    static int no;

    // hàm đệ quy để tìm giải pháp
    static void nQueens(int k, int n)
    {
        // thử tất cả các vị trí có thể cho quân hậu ở hàng hiện tại
        for (int i = 1; i <= n; i++)
        {
            // kiểm tra xem có thể đặt quân hậu ở vị trí hiện tại không
            if (canPlace(k, i))
            {
                // đặt quân hậu ở vị trí hiện tại
                arr[k] = i;

                // nếu tất cả các quân hậu được đặt, hiển thị giải pháp
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // đệ quy thử đặt các quân hậu còn lại
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // hàm trợ giúp để kiểm tra xem có thể đặt quân hậu ở vị trí hiện tại không
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // kiểm tra xem quân hậu đã được đặt ở cùng cột hoặc đường chéo chưa
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // hàm để hiển thị giải pháp
    static void display(int n)
    {
        breakLine();
        Console.Write("Arrangement No. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // in '_' cho ô trống và 'Q' cho ô có quân hậu
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // Mã Driver để khởi tạo bài toán và gọi hàm đệ quy
    public static void Main(String[] args)
    {
        int n = 4; // kích thước của bàn cờ
        nQueens(1, n);
    }
}
