Ý tưởng là tạo ra tất cả các số nguyên tố nhỏ hơn hoặc bằng số N đã cho bằng cách sử dụng sàng Eratosthenes. Sau khi đã tạo ra tất cả các số nguyên tố như vậy, chúng ta lưu trữ tất cả chúng trong một mảng và in tất cả các số nguyên tố chiếm các vị trí số nguyên tố. Dưới đây là một triển khai bằng Python:

```
# Chương trình Python để in các siêu số nguyên tố nhỏ hơn hoặc bằng n.

# Tạo tất cả các số nguyên tố nhỏ hơn n bằng cách sử dụng sàng Eratosthenes.
def sieve(n):
    is_prime = [True for i in range(n+1)]
    is_prime[0] = False
    is_prime[1] = False

    for p in range(2,n+1):
        if is_prime[p]:
            for i in range(2*p, n+1, p):
                is_prime[i] = False

    return is_prime

def super_primes(n):
    # Tạo tất cả các số nguyên tố
    is_prime = sieve(n)

    # Lưu trữ tất cả các số nguyên tố trong một mảng
    primes = [i for i, prime in enumerate(is_prime) if prime]
    primes = [0] + primes
    for i, p in enumerate(primes):
        if is_prime[i]:
            yield p
```

Thuật toán Dijkstra rất giống với thuật toán Prim cho cây bao trùm tối thiểu. Tương tự như MST của Prim, tạo ra một SPT (cây đường đi ngắn nhất) với một nguồn gốc cho trước làm gốc. Duy trì hai tập hợp, một tập hợp chứa các đỉnh nằm trong cây đường đi ngắn nhất, tập hợp còn lại chứa các đỉnh chưa được đưa vào cây đường đi ngắn nhất. Ở mỗi bước của thuật toán, tìm một đỉnh nằm trong tập hợp còn lại (tập hợp chưa được đưa vào) và có khoảng cách tối thiểu từ nguồn.

```c
// Chương trình nhằm mục đích triển khai thuật toán đường đi ngắn nhất từ một nguồn duy nhất của Dijkstra bằng ngôn ngữ C.
// Chương trình sử dụng ma trận kề làm biểu diễn của đồ thị.

#include <limits.h>
#include <stdbool.h>
#include <stdio.h>

// Số lượng đỉnh có trong một đồ thị.
#define V 9

// Một hàm được sử dụng để xác định đỉnh có giá trị khoảng cách nhỏ nhất
// trong một tập hợp các đỉnh chưa được đưa vào cây đường đi ngắn nhất.
int findMinDistance(int dist[], bool sptSet[])
{
    // Khởi tạo giá trị min
    int min = INT_MAX, min_index;

    for (int v = 0; v < V; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;
    return min_index;
}

// Một hàm tiện ích để in mảng khoảng cách được xây dựng
void printSolution(int dist[])
{
    printf("Vertex \t\t Khoảng cách từ Nguồn\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t\t\t %d\n", i, dist[i]);
}

// một hàm áp dụng thuật toán Dijkstra để tìm đường đi ngắn nhất giữa
// một nút nguồn duy nhất và tất cả các nút khác trong một đồ thị. Đồ thị được biểu diễn bằng
// một ma trận kề.
void dijkstra(int graph[V][V], int src)
{
    int dist[V];
    bool processed[V];
    int i, u, v;

    // Khởi tạo tất cả các khoảng cách là vô cực và đã xử lý là sai
    for (i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        processed[i] = false;
    }

    // Khoảng cách của đỉnh nguồn từ chính nó luôn là 0
    dist[src] = 0;

    // Tìm đường đi ngắn nhất cho tất cả các đỉnh
    for (i = 0; i < V - 1; i++) {
        // Chọn đỉnh có khoảng cách tối thiểu từ tập hợp các đỉnh chưa được xử lý
        u = -1;
        for (i = 0; i < V; i++) {
            if (!processed[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }

        // Đánh dấu đỉnh đã chọn là đã xử lý
        processed[u] = true;

        // Cập nhật giá trị dist của các đỉnh kề của đỉnh đã chọn
        for (v = 0; v < V; v++) {
            if (graph[u][v] != 0 && !processed[v]) {
                int new_dist = dist[u] + graph[u][v];
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                }
            }
        }
    }

    // In mảng khoảng cách được xây dựng
    printSolution(dist);
}


int main()
{
    /*  Tạo đồ thị ví dụ */
    int graph[V][V] = { { 0, 4, 0, 0, 0, 0, 0, 8, 0 },
                        { 4, 0, 8, 0, 0, 0, 0, 11, 0 },
                        { 0, 8, 0, 7, 0, 4, 0, 0, 2 },
                        { 0, 0, 7, 0, 9, 14, 0, 0, 0 },
                        { 0, 0, 0, 9, 0, 10, 0, 0, 0 },
                        { 0, 0, 4, 14, 10, 0, 2, 0, 0 },
                        { 0, 0, 0, 0, 0, 2, 0, 1, 6 },
                        { 8, 11, 0, 0, 0, 0, 1, 0, 7 },
                        { 0, 0, 2, 0, 0, 0, 6, 7, 0 } };

        // Gọi hàm
        dijkstra(graph, 0);

        return 0;
}
```

Đầu ra dự kiến của đoạn mã trên là
```
Vertex          Khoảng cách từ Nguồn
0                  0
1                  4
2                  12
3                  19
4                  21
5                  11
6                  9
7                  8
8                  14
```

Độ phức tạp thời gian của thuật toán này là O(V^2) và không gian phụ trợ cần thiết cho thuật toán này là O(V).

