Mục tiêu là thiết lập con đường tiết kiệm chi phí nhất kết nối tất cả các thành phố. Để đạt được điều này, chúng ta cần xác định Cây khung nhỏ nhất (MST) của bản đồ thành phố, coi mỗi thành phố là một nút trên đồ thị và tất cả các con đường bị hư hỏng là các cạnh. Tổng chi phí của con đường là tổng các giá trị cạnh trong Cây khung nhỏ nhất.

```
// Mã Java để tìm con đường
// chi phí tối thiểu để kết nối tất cả các thành phố
import java.util.* ;

class GFG{

    // Hàm tìm nút có giá trị nhỏ nhất
    // trong số các nút chưa được thêm vào MST

    static int minNode(int n, int keyvals[], boolean mstset[])
    {
        int min_val = Integer.MAX_VALUE;
        int min_index = 0;

        // Lặp qua tất cả các giá trị của các nút, 
        // mà chưa được thêm vào MST và tìm nút có giá trị nhỏ nhất.
        for(int i = 0; i < n; i++)
        {
            if (mstset[i] == false && keyvals[i] < min_val)
            {
                min_val = keyvals[i];
                min_index = i;
            }
        }
        return min_index;
    }

    // Hàm tìm MST và
    // chi phí của MST.
    static void findCost(int n, int city[][])
    {

        // Mảng lưu trữ các nút cha.
        int parent[] = new int[n];

        // Mảng lưu trữ giá trị khóa của mỗi nút.
        int keyvals[] = new int[n];

        // Mảng Boolean để chỉ ra một nút có được bao gồm trong MST hay không.
        boolean mstset[] = new boolean[n];

        // Đặt tất cả các giá trị khóa thành vô cùng và không có nút nào được bao gồm trong MST.
        for(int i = 0; i < n; i++)
        {
            keyvals[i] = Integer.MAX_VALUE;
            mstset[i] = false;
        }

        // Bắt đầu tìm MST từ nút 0.
        // Cha của nút 0 là không có và được đặt thành -1.
        // giá trị khóa hoặc chi phí tối thiểu để đến nút thứ 0 từ nút thứ 0 là 0.
        parent[0] = -1;
        keyvals[0] = 0;

        // Tìm n-1 nút còn lại của MST.
        for(int i = 0; i < n - 1; i++)
        {    
            // Đầu tiên tìm nút nhỏ nhất trong số các nút chưa được bao gồm trong MST.
            int u = minNode(n, keyvals, mstset);

            // Bao gồm nút thứ u trong MST.
            mstset[u] = true;

            // Cập nhật các giá trị của các nút lân cận của u chưa được bao gồm trong MST.
            for(int v = 0; v < n; v++)
            {
                if (city[u][v] > 0 && mstset[v] == false && city[u][v] < keyvals[v])
                {
                    keyvals[v] = city[u][v];
                    parent[v] = u;
                }
            }
        }

        // Tìm chi phí bằng cách cộng các giá trị cạnh của MST.
        int cost = 0;
        for(int i = 1; i < n; i++)
            cost += city[parent[i]][i];

        System.out.println(cost);
    }

    // Mã trình điều khiển
    public static void main(String args[])
    {

        // Đầu vào 1
        int n1 = 5;
        int city1[][] = { { 0, 1, 2, 3, 4 },
                        { 1, 0, 5, 0, 7 },
                        { 2, 5, 0, 6, 0 },
                        { 3, 0, 6, 0, 0 },
                        { 4, 7, 0, 0, 0 } };

        findCost(n1, city1);

        // Đầu vào 2
        int n2 = 6;
        int city2[][] = { { 0, 1, 1, 100, 0, 0 },
                        { 1, 0, 1, 0, 0, 0 },
                        { 1, 1, 0, 0, 0, 0 },
                        { 100, 0, 0, 0, 2, 2 },
                        { 0, 0, 0, 2, 0, 2 },
                        { 0, 0, 0, 2, 2, 0 } };

        findCost(n2, city2);

    }
}
```

